// src/App.js
import React from 'react';
import './styles/App.css';

function App() {
    return (
        <div className="app">
            <header className="app-header">
                <h1>🏥 E-Health System</h1>
            </header>
            <main className="app-main">
                <p>Welcome to E-Health System</p>
            </main>
        </div>
    );
}

export default App;
